def upload_video():
    if request.method == "POST":
        file = request.files["file"]
        filename = secure_filename(file.filename)
        file.save(os.path.join("videos", filename))
        video = Video(title=request.form["title"], filename=filename, resolution=request.form["resolution"])
        db.session.add(video)
        db.session.commit()
        return "Video uploaded successfully"

def get_video_stream(video_id):
    video_stream = VideoStream(video_id)
    return send_file(video_stream.file_path, mimetype="video/mp4", as_attachment=True)

def get_video_stream_chunked(video_id):
    video_stream = VideoStream(video_id)
    return app.response_class(video_stream.stream(), mimetype="video/mp4")

@app.route("/upload", methods=["POST"])
def upload():
    return upload_video()

@app.route("/video/<int:video_id>", methods=["GET"])
def get_video(video_id):
    return get_video_stream(video_id)

@app.route("/video/<int:video_id>/chunked", methods=["GET"])
def get_video_chunked(video_id):
    return get_video_stream_chunked(video_id)

if __name__ == "__main__":
    app.run(debug=True, threaded=True)

class VideoStream:
    def __init__(self, video_file, resolution):
        self.video_file = video_file
        self.resolution = resolution
        self.position = 0

    def play(self):
        return self.stream_video()

    def pause(self):
        return self.pause_video()

    def restart(self):
        self.position = 0
        return self.stream_video()

    def skip_forwards(self, seconds):
        self.position += seconds
        return self.stream_video()

    def skip_backwards(self, seconds):
        self.position -= seconds
        if self.position < 0:
            self.position = 0
        return self.stream_video()

    def stream_video(self):
        try:
            with open(self.video_file, 'rb') as file:
                file.seek(self.position)
                chunk = file.read(1024)
                while chunk:
                    yield chunk
                    self.position += len(chunk)
                    chunk = file.read(1024)
        except Exception as e:
            print(f"Error streaming video: {e}")

