import threading
from queue import Queue

class VideoStreamingServer:
    def __init__(self):
        self.service = VideoStreamingService()
        self.queue = Queue()

    def start(self):
        threading.Thread(target=self.process_requests).start()

    def process_requests(self):
        while True:
            request = self.queue.get()
            if request['type'] == 'upload':
                video_id = self.service.upload_video(request['video_file'], request['resolution'])
                print(f"Video uploaded with id {video_id}")
            elif request['type'] == 'get':
                video = self.service.get_video(request['video_id'])
                if video:
                    print(f"Video found with id {request['video_id']}")
                else:
                    print(f"Video not found with id {request['video_id']}")
            elif request['type'] == 'delete':
                self.service.delete_video(request['video_id'])
                print(f"Video deleted with id {request['video_id']}")
            elif request['type'] == 'play':
                video = self.service.get_video(request['video_id'])
                if video:
                    for chunk in video.play():
                        print(f"Streaming video chunk: {chunk}")
                else:
                    print(f"Video not found with id {request['video_id']}")
            self.queue.task_done()

    def upload_video(self, video_file, resolution):
        self.queue.put({'type': 'upload', 'video_file': video_file, 'resolution': resolution})

    def get_video(self, video_id):
        self.queue.put({'type': 'get', 'video_id': video_id})

    def delete_video(self, video_id):
        self.queue.put({'type': 'delete', 'video_id': video_id})

    def play_video(self, video_id):
        self.queue.put({'type': 'play', 'video_id': video_id})

