class Connection:
    def __init__(self, quality):
        self.quality = quality

    def get_quality(self):
        return self.quality

class VideoStreamingServer:
    def __init__(self):
        self.service = VideoStreamingService()
        self.connections = {}

    def add_connection(self, user_id, connection):
        self.connections[user_id] = connection

    def remove_connection(self, user_id):
        if user_id in self.connections:
            del self.connections[user_id]

    def stream_video(self, user_id, video_id, resolution):
        video = self.service.get_video(video_id)
        if video:
            connection = self.connections.get(user_id)
            if connection:
                quality = connection.get_quality()
                if quality == "low":
                    resolution = min(resolution, 480)
                elif quality == "medium":
                    resolution = min(resolution, 720)
                elif quality == "high":
                    resolution = min(resolution, 1080)
                stream = VideoStream(video, resolution)
                stream.play()
                return stream
            else:
                print("No connection found for user")
        else:
            print("No video found")

    def handle_request(self, user_id, video_id, resolution, action, seconds=0):
        stream = self.stream_video(user_id, video_id, resolution)
        if stream:
            if action == "play":
                stream.play()
            elif action == "pause":
                stream.pause()
            elif action == "restart":
                stream.restart()
            elif action == "skip_forwards":
                stream.skip_forwards(seconds)
            elif action == "skip_backwards":
                stream.skip_backwards(seconds)

