            del self.videos[video_id]

    def get_video(self, video_id):
        return self.videos.get(video_id)

    def start_stream(self, video_id, resolution, user_id):
        video = self.get_video(video_id)
        if video:
            if video_id not in self.streams:
                self.streams[video_id] = {}
            if user_id not in self.streams[video_id]:
                self.streams[video_id][user_id] = {'resolution': resolution, 'position': 0}
            return True
        return False

    def pause_stream(self, video_id, user_id):
        if video_id in self.streams and user_id in self.streams[video_id]:
            self.streams[video_id][user_id]['paused'] = True
            return True
        return False

    def resume_stream(self, video_id, user_id):
        if video_id in self.streams and user_id in self.streams[video_id]:
            if 'paused' in self.streams[video_id][user_id]:
                del self.streams[video_id][user_id]['paused']
            return True
        return False

    def skip_forwards(self, video_id, user_id, seconds):
        if video_id in self.streams and user_id in self.streams[video_id]:
            self.streams[video_id][user_id]['position'] += seconds
            return True
        return False

    def skip_backwards(self, video_id, user_id, seconds):
        if video_id in self.streams and user_id in self.streams[video_id]:
            self.streams[video_id][user_id]['position'] -= seconds
            if self.streams[video_id][user_id]['position'] < 0:
                self.streams[video_id][user_id]['position'] = 0
            return True
        return False

    def get_stream(self, video_id, user_id):
        if video_id in self.streams and user_id in self.streams[video_id]:
            return self.streams[video_id][user_id]
