# define video storage path
VIDEO_STORAGE_PATH = 'videos/'

# define allowed video extensions
ALLOWED_EXTENSIONS = {'mp4', 'avi', 'mkv', 'mov'}

# lock for thread-safe video access
video_lock = threading.Lock()

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def get_video_info(video_id):
    with video_lock:
        video_path = os.path.join(VIDEO_STORAGE_PATH, video_id)
        if os.path.exists(video_path):
            return {'exists': True, 'size': os.path.getsize(video_path)}
        else:
            return {'exists': False}

def stream_video(video_id, start_time=0, end_time=None):
    with video_lock:
        video_path = os.path.join(VIDEO_STORAGE_PATH, video_id)
        if os.path.exists(video_path):
            video_file = open(video_path, 'rb')
            video_file.seek(start_time)
            chunk_size = 1024 * 1024
            while True:
                chunk = video_file.read(chunk_size)
                if not chunk:
                    break
                yield chunk
            video_file.close()
        else:
            return 'Video not found'

def upload_video(video_file, video_id):
    with video_lock:
        if video_file and allowed_file(video_file.filename):
            filename = secure_filename(video_file.filename)
            video_file.save(os.path.join(VIDEO_STORAGE_PATH, video_id))
            return 'Video uploaded successfully'
        else:
            return 'Invalid video file'

def delete_video(video_id):
    with video_lock:
        video_path = os.path.join(VIDEO_STORAGE_PATH, video_id)
        if os.path.exists(video_path):
            os.remove(video_path)
            return 'Video deleted successfully'
        else:
            return 'Video not found'

